1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	const BLOCK_SIZE = 3;
15	const BLOCK_PREMIUM = 60;
16	
17	function typePremium(type: string, count: number): number {
18	  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
19	    return BLOCK_PREMIUM;
20	  }
21	  return count * (BASE_PREMIUMS[type] ?? 0);
22	}
23	
24	function countByType(items: Array<{ type: string }>): Record<string, number> {
25	  const counts: Record<string, number> = {};
26	  for (const item of items) {
27	    counts[item.type] = (counts[item.type] ?? 0) + 1;
28	  }
29	  return counts;
30	}
31	
32	const CURSED_SURCHARGE_RATE = 0.5;
33	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
34	const HIGH_ENCHANTMENT_THRESHOLD = 5;
35	
36	function surchargeTotal<T extends { type: string }>(
37	  items: T[],
38	  appliesTo: (item: T) => boolean,
39	  rate: number,
40	): number {
41	  let total = 0;
42	  for (const item of items) {
43	    if (appliesTo(item)) {
44	      total += (BASE_PREMIUMS[item.type] ?? 0) * rate;
45	    }
46	  }
47	  return total;
48	}
49	
50	function cursedSurchargeTotal(items: Array<{ type: string; cursed?: boolean }>): number {
51	  return surchargeTotal(items, (item) => !!item.cursed, CURSED_SURCHARGE_RATE);
52	}
53	
54	function highEnchantmentSurchargeTotal(items: Array<{ type: string; enchantment?: number }>): number {
55	  return surchargeTotal(
56	    items,
57	    (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
58	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
59	  );
60	}
61	
62	function calculateQuotePremium(items: Array<{ type: string; cursed?: boolean; enchantment?: number }>): number {
63	  const countsByType = countByType(items);
64	
65	  let policyBasePremium = 0;
66	  for (const [type, count] of Object.entries(countsByType)) {
67	    policyBasePremium += typePremium(type, count);
68	  }
69	
70	  const itemAdjustedTotal = policyBasePremium + cursedSurchargeTotal(items) + highEnchantmentSurchargeTotal(items);
71	
72	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_RATE;
73	  const rawPremium = itemAdjustedTotal + firstInsuranceSurcharge + PROCESSING_FEE;
74	  return Math.ceil(rawPremium);
75	}
76	
77	interface QuoteResult {
78	  premium: number;
79	}
80	
81	interface ScenarioOutcome {
82	  results: QuoteResult[];
83	}
84	
85	export function processScenario(scenario: {
86	  customer: { yearsWithMHPCO: number };
87	  steps: Array<{ op: string; items?: Array<{ type: string; cursed?: boolean; enchantment?: number }> }>;
88	}): ScenarioOutcome {
89	  return {
90	    results: scenario.steps.map((step) => ({
91	      premium: calculateQuotePremium(step.items ?? []),
92	    })),
93	  };
94	}
